import{_ as e,o as a,c as p,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const C=JSON.parse('{"title":"荒野猎人-战纹","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/荒野猎人/荒野猎人-战纹.md","filePath":"4.资源分区/6.技艺及称号/射击类/荒野猎人/荒野猎人-战纹.md"}'),s={name:"4.资源分区/6.技艺及称号/射击类/荒野猎人/荒野猎人-战纹.md"};function o(d,b,_,l,i,c){return a(),p("div",null,[...b[0]||(b[0]=[r("h1",{id:"荒野猎人-战纹",tabindex:"-1"},[t("荒野猎人-战纹 "),r("a",{class:"header-anchor",href:"#荒野猎人-战纹","aria-label":'Permalink to "荒野猎人-战纹"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘002A")])])],-1),n('<h1 id="荒野猎人-战纹-1" tabindex="-1">荒野猎人-战纹 <a class="header-anchor" href="#荒野猎人-战纹-1" aria-label="Permalink to &quot;荒野猎人-战纹&quot;">​</a></h1><p>战纹<br> 战纹，一般而言是涂抹在荒野猎人面部的特殊花纹，一方面能起到巫术上的祭祀作用，另一方面则展示了荒野猎人的勇气。<br> 荒野猎人可以在主神空间中购买战纹图纸和材料，并根据图纸上的图案为自己涂画战纹，也可以尝试创造一种新的战纹。特殊的，创造战纹本身属于一种自创能力，因此，由ST裁定是否开放创造战纹的能力。<br> 每次涂画战纹后，这道战纹都可以保持一个影片的时间，在绘制完成后的下个影片结束时将不再保持它的效力，只能重新涂画，战纹的效果并不会叠加。<br> 涂画战纹是一件相当繁琐的事情，因此只能在主神空间中进行这项工作。涂画战纹需要使用风度-手艺-专业：绘画来进行一个类造物检定。涂画战纹是一个根据战纹支线等级增加时长的延长检定，当延长检定数累计通过对应涂画难度时，视为成功涂画；当四次延长检定的成功数未通过时，则视为涂画失败，且下场影片结束前不能再尝试。<br> 无支线 15分钟 12DC 1小时<br> D级 30分钟 20DC 2小时<br> C级 1小时 52DC 4小时<br> B级 2小时 84DC 8小时<br> A级 4小时 120DC 16小时<br> S级 6小时 169DC 1天</p><p>战纹分为三个部分，分别是主纹、副纹、侧纹。一个战纹可以没有副纹和侧纹，但不能没有主纹，因此，只涂画副纹和侧纹无法正常的被称为战纹，也不能生效。只有主纹的战纹会被称为简易战纹；同时具有主纹和副纹/侧纹的战纹会被称为战斗战纹；同时具有主纹、副纹、侧纹的战纹会被称为华丽战纹。一道战纹只能拥有一种主纹、两种副纹（且不能为相同等级）和不超过主纹等级数的侧纹（D1C2B3A4S5）。<br> 有些纹路在图纸中记载具有【战斗战纹】或【华丽战纹】的字样，意为只有满足构成战纹的纹路时才能生效（例：玩家皇帝同时购买并涂画了主纹和副纹，那么他可以触发【战斗战纹】）。重复的涂画同一种主纹会增加荒野猎人对这种纹路的感应，从而获得更多效果，具体由图纸记载，所有的纹路都不会提供属性点，若猎人主动用任何会遮挡战纹的东西遮挡住战纹，或在影片中洗去战纹，那么战纹都将无法生效，直至战纹重新完整的露出或在影片中重新绘制战纹为止。</p><p>图纸：</p><p>主纹<br> 主纹在购买时也可以不以其记载的主属性进行购买，战车对应生理三属性、弄臣对应心智三属性、死神对应互动三属性，在购买时也可以选择一项相对应且属于该属性分类的属性作为战纹的主属性购买。（例：玩家皇帝以敏捷作为主属性购买了战车的怒火，则将其中所有的“力量”替换为“敏捷”）</p><p>战车的怒火<br> D+500<br> 这是一道黑红色的浓重主纹，丝毫不加修饰，似乎是将颜料随意的涂抹在脸上，但其中隐含着战车的恨意与力量。<br> 主纹效果：荒野猎人在力量检定上获得等同于其力量附加*2的表现加值<br> 【战斗战纹】：再获得等同于其力量附加的表现加值<br> 【华丽战纹】：在【战斗战纹】的基础上再获得等同于其力量附加的表现加值</p><p>弄臣的把戏<br> D+500<br> 这是一道靛蓝色的浓重主纹，几笔勾勒突显出其主人的狡诈多智，其中蕴藏着弄臣的诡诈把戏。<br> 主纹效果：荒野猎人在智力检定上获得等同于其智力附加*2的表现加值<br> 【战斗战纹】：再获得等同于其智力附加的表现加值<br> 【华丽战纹】：在【战斗战纹】的基础上再获得等同于其智力附加的表现加值</p><p>死神的垂怜<br> D+500<br> 这是一道暗黄色的浓重主纹，似是悲悯的死神之镰划过一般平整，其中暗示着死神对不可违抗命运的垂怜。<br> 主纹效果：荒野猎人在风度检定上获得等同于其风度附加*2的表现加值<br> 【战斗战纹】：再获得等同于其风度附加的表现加值<br> 【华丽战纹】：在【战斗战纹】的基础上再获得等同于其风度附加的表现加值</p><p>通灵巫术<br> D+500<br> 通灵巫术不是一种主纹，而是一种增强主纹的能力，会正常提供内在属性，在购买通灵巫术后，选择一种已购买的主纹，你每绘制成功这种主纹并经过1场影片，就会对其中沉眠的先祖之灵进一步通感，并增加1点该主纹对应主属性检定上的2点修行加值。选择的那种主纹将在涂画成功的前提下经过3/5/7/9场影片后变为C/B/A/S级，这并不会真正的增加它的支线等级和制造难度，只会影响最多涂画的侧纹个数。</p><p>副纹<br> C级<br> 饥渴圣杯<br> C+1000<br> 这是两团涂于颧骨之上的殷红色战纹，像是戏剧中的小丑的妆容，但又像是两滴血泪，挂在凄惨的笑容上。<br> 饥渴圣杯会为猎人提供等同于人物最高支线等级数量（C2B4A6S8）点吸血，饥渴的圣杯为猎人带来不眠不休的能力，猎人在影片中将无需睡眠、进食和呼吸。</p><p>戮敌宝剑<br> C+1000<br> 这是两道描在眉锋上的深蓝色战纹，像是两道眉间绘制出的宝剑。<br> 戮敌宝剑在猎人使用符合猎人的猎具武器（如猎枪、猎弓、猎刀等）时，会为猎人提供对被攻击者等同于人物最高支线等级的C/B/A/S级先制效果，戮敌的宝剑为猎人带来孜孜不倦的追踪能力，猎人在对被其击伤过且仍未完全恢复至正常状态的敌人进行追踪检定时，额外再获得6点检定加值。</p><p>统御权杖<br> C+1000<br> 这是一条涂抹在鼻梁上的明黄色战纹，像是一条统御一切，发号施令的权杖。<br> 统御权杖在猎人驾驶坐骑进行移动时，以一个迅捷动作使用，可以操控坐骑再进行一次距离不超过坐骑移动速度的移动。 只有在上一轮你操控过这匹坐骑进行移动才能使用。<br> 每轮限一次，猎人可以将其拥有的一个基础花招动作升级为仅能用于驾驶坐骑和应用驾驶坐骑相关能力的迅捷动作。</p><p>运势星币<br> C+1000<br> 这是一团涂抹在唇边的暗紫色战纹，像是一枚无比神秘的，掌握着运势与造化的星币。<br> 运势星币在每轮至多可以应用一次，在一次攻击检定后，猎人可以选择重投那次检定，并比较两次检定的结果，从中选择一次生效。</p><p>B级<br> 热血战歌<br> B+2000<br> 这是几条画在面颊两边的多色战纹，似乎有什么东西在不停搏动的力量，像是一首振奋人心的战歌。<br> 热血战歌在猎人使用近战猎人武器时可以生效。猎人使用的符合条件的近战猎人武器攻击时，可以再以一个自由动作进行一次侦查检定以定位其敏感范围内的所有敌人，这视为一个B级命运来源的侦测效果，且猎人具有A级目盲免疫的效果。</p><p>先祖祭礼<br> B+2000<br> 这是几条画在面颊两边的纯色战纹，似乎有什么东西在接受祭祀一般，像是一场玄秘的祭礼。<br> 先祖祭礼在猎人使用远程猎人武器时可以生效。猎人在攻击后的那轮中若仍保留着迅捷动作到回合外，则在其下一次受到攻击时可以消耗一个反射动作进行一次招架，若如此做且成功招架，则猎人在接下来的这个战斗场景中即使不保有任何完好也不会昏迷。</p><p>渎神仪式<br> B+2000<br> 这是几条画在面颊两边的黑色战纹，似乎有什么东西在暗自谋划渎神之事一般，像是一场邪恶的仪式。<br> 渎神仪式在猎人使用巫术时可以生效。猎人的巫术攻击时可以将其所有的伤害出目转换为毒素点数，并具有【毁灭】效果。</p><p>S级<br> 荒野之心<br> S+8000<br> 这是涂画在整个面部的彩色战纹，蕴藏着荒野的全部力量，如同荒野之心一般无时无刻的跳动着。<br> 每日限一次，荒野猎人死亡时，肉身将自动腐烂归于大地，并立刻在原地复活，这是一个S级、环境来源的复活效果。若在当前场景中荒野猎人第二次死亡，则在本场影片中不会再复活，但相应的，荒野猎人的尸身不会损坏。</p><p>侧纹<br> 侧纹的价格均为750分，但视为一个D级难度，购买侧纹时需先掷一次十三面骰，从前到后根据出目决定购买了哪一种侧纹，在购买后，下一次掷骰时少掷等同于购买数量的面数，并自动跳过已购买的侧纹。</p><p>1.获得2闪避防御<br> 2.获得2点攻击检定表现加值<br> 3.获得灵感视觉<br> 4.远程猎人武器获得2点高速<br> 5.近战猎人武器获得2点破甲<br> 6.获得4点强韧检定表现加值<br> 7.每个你的回合开始时，若你不具有临时生命，则获得1点临时生命<br> 8.使用弓进行攻击时，还可以对射程范围内最多两个敌人同时进行攻击<br> 9.获得2点追踪检定表现加值<br> 10.获得一个仅能用来搭箭的花招动作<br> 11.你将可以用跳跃代替行走<br> 12.猎人巫术获得2点破魔<br> 13.猎人武器提升1点武器伤害</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const D=e(s,[["render",o]]);export{C as __pageData,D as default};
